#!/usr/bin/env python3\n\"\"\"\nData Generation Module\nTranslates R's simulate_data.R to Python\n\nOriginal R script:\n  - n_buyer = 10 (or 1,000,000)\n  - S = 375 (state dimensions)\n  - A = 25 (action dimensions)\n  - Outputs: 778 columns (buyer_id, receive_time_id, states, actions, next_states, outcome)\n\nAuthor: Replication Project\nDate: 2026-04-29\n\"\"\"\n\nimport os\nimport sys\nimport numpy as np\nimport pandas as pd\nimport logging\nfrom pathlib import Path\nfrom typing import Tuple, Dict, List\n\n# Setup logging\nlogging.basicConfig(\n    level=logging.INFO,\n    format='%(asctime)s - %(levelname)s - %(message)s',\n    handlers=[\n        logging.FileHandler('logs/data_generation.log'),\n        logging.StreamHandler()\n    ]\n)\nlogger = logging.getLogger(__name__)\n\n# Create directories if they don't exist\nPath('data/raw').mkdir(parents=True, exist_ok=True)\nPath('logs').mkdir(parents=True, exist_ok=True)\nPath('output/tables').mkdir(parents=True, exist_ok=True)\n\n\ndef generate_simulated_data(\n    n_buyer: int = 10,\n    S: int = 375,\n    A: int = 25,\n    seed: int = 42,\n    verbose: bool = True\n) -> pd.DataFrame:\n    \"\"\"\n    Generate simulated data matching R's simulate_data.R\n    \n    This function replicates the exact data generation process from the R script:\n    1. Generate trajectory lengths per buyer: n_t ~ N(25, 5), min=10\n    2. Create buyer and time identifiers\n    3. Generate state features: S dimensions, ~N(0, 1)\n    4. Generate actions: uniformly sampled from 1 to A\n    5. One-hot encode actions\n    6. Generate next-state features (lead operation)\n    7. Generate outcome: max(0, N(-2, 2))\n    \n    Parameters\n    ----------\n    n_buyer : int\n        Number of buyers (default 10 for testing, 1,000,000 in production)\n    S : int\n        Number of state dimensions (default 375)\n    A : int\n        Number of action dimensions (coupons)\n    seed : int\n        Random seed for reproducibility\n    verbose : bool\n        Print progress messages\n    \n    Returns\n    -------\n    pd.DataFrame\n        DataFrame with 778 columns:\n        - buyer_id (1)\n        - receive_time_id (1)\n        - state features (375)\n        - action dummies (25)\n        - next-state features (375)\n        - outcome (1)\n    \n    Notes\n    -----\n    - Total rows: sum(n_t) where n_t ~ N(25, 5), min=10\n    - Total columns: 2 + 375 + 25 + 375 + 1 = 778\n    \"\"\"\n    \n    logger.info(f\"Generating simulated data: n_buyer={n_buyer}, S={S}, A={A}, seed={seed}\")\n    np.random.seed(seed)\n    \n    # ========== STEP 1: Generate trajectory lengths ==========\n    if verbose:\n        logger.info(\"Step 1: Generating trajectory lengths...\")\n    \n    # n_t ~ N(25, 5), min=10\n    n_t = np.round(np.random.normal(25, 5, n_buyer)).astype(int)\n    n_t = np.maximum(n_t, 10)  # Ensure minimum of 10\n    n_row = n_t.sum()\n    \n    logger.info(f\"  Generated {n_row} total observations from {n_buyer} buyers\")\n    logger.info(f\"  Trajectory lengths: mean={n_t.mean():.1f}, min={n_t.min()}, max={n_t.max()}\")\n    \n    # ========== STEP 2: Create base structure (buyer_id, receive_time_id) ==========\n    if verbose:\n        logger.info(\"Step 2: Creating buyer and time identifiers...\")\n    \n    buyer_ids = np.repeat(np.arange(1, n_buyer + 1), n_t)\n    receive_time_ids = np.concatenate([np.arange(1, t + 1) for t in n_t])\n    \n    df = pd.DataFrame({\n        'buyer_id': buyer_ids,\n        'receive_time_id': receive_time_ids\n    })\n    \n    # ========== STEP 3: Generate state features (375 columns) ==========\n    if verbose:\n        logger.info(\"Step 3: Generating state features...\")\n    \n    # state ~ N(0, 1), rounded to 2 decimals\n    state_data = np.round(np.random.normal(0, 1, (n_row, S)), 2)\n    state_df = pd.DataFrame(\n        state_data,\n        columns=[f's{i+1}' for i in range(S)]\n    )\n    df = pd.concat([df, state_df], axis=1)\n    \n    logger.info(f\"  Generated {S} state columns\")\n    logger.info(f\"  State summary: mean={state_data.mean():.3f}, std={state_data.std():.3f}\")\n    \n    # ========== STEP 4: Generate actions and one-hot encode (25 columns) ==========\n    if verbose:\n        logger.info(\"Step 4: Generating and encoding actions...\")\n    \n    # action ~ floor(Uniform(1, 26)) i.e., {1, 2, ..., 25}\n    actions_raw = np.floor(np.random.uniform(1, 26, n_row)).astype(int)\n    \n    # One-hot encode: creates columns a1, a2, ..., a25\n    action_onehot = pd.get_dummies(actions_raw, prefix='a', drop_first=False).astype(int)\n    \n    # Ensure all 25 actions are represented in columns\n    for i in range(1, A + 1):\n        if f'a{i}' not in action_onehot.columns:\n            action_onehot[f'a{i}'] = 0\n    \n    # Reorder columns to match expected order\n    action_onehot = action_onehot[[f'a{i}' for i in range(1, A + 1)]]\n    df = pd.concat([df, action_onehot], axis=1)\n    \n    logger.info(f\"  Generated {A} action dummy columns\")\n    logger.info(f\"  Action distribution: {pd.Series(actions_raw).value_counts().to_dict()}\")\n    \n    # ========== STEP 5: Generate next-state features (375 columns) ==========\n    if verbose:\n        logger.info(\"Step 5: Generating next-state features (lead operation)...\")\n    \n    # Create next-state by shifting within each buyer\n    next_state_df = pd.DataFrame(index=range(n_row))\n    \n    for col in range(1, S + 1):\n        state_col = f's{col}'\n        next_state_col = f'ns{col}'\n        \n        # Shift -1 to get next observation, but handle group boundaries\n        shifted = df.groupby('buyer_id')[state_col].shift(-1)\n        next_state_df[next_state_col] = shifted\n    \n    df = pd.concat([df, next_state_df], axis=1)\n    \n    logger.info(f\"  Generated {S} next-state columns\")\n    logger.info(f\"  Last observations per buyer have NA in next-state (expected)\")\n    \n    # ========== STEP 6: Generate outcome (1 column) ==========\n    if verbose:\n        logger.info(\"Step 6: Generating outcome variable...\")\n    \n    # div_pay_amt_fillna = max(0, N(-2, 2))\n    outcome = np.maximum(0, np.random.normal(-2, 2, n_row))\n    df['div_pay_amt_fillna'] = outcome\n    \n    logger.info(f\"  Generated outcome column\")\n    logger.info(f\"  Outcome summary: mean={outcome.mean():.3f}, std={outcome.std():.3f}, \"\n                f\"min={outcome.min():.3f}, max={outcome.max():.3f}\")\n    \n    # ========== STEP 7: Validation ==========\n    if verbose:\n        logger.info(\"Step 7: Validating data structure...\")\n    \n    errors = validate_simulated_data(df, n_buyer, S, A, n_row)\n    if errors:\n        logger.error(\"Validation errors detected:\")\n        for error in errors:\n            logger.error(f\"  - {error}\")\n        raise ValueError(\"Data validation failed\")\n    else:\n        logger.info(\"  ✓ All validation checks passed\")\n    \n    logger.info(f\"\\nData generation complete!\")\n    logger.info(f\"  Shape: {df.shape}\")\n    logger.info(f\"  Columns: {df.shape[1]} (expected: 778)\")\n    logger.info(f\"  Rows: {df.shape[0]}\")\n    \n    return df\n\n\ndef validate_simulated_data(\n    df: pd.DataFrame,\n    n_buyer: int,\n    S: int,\n    A: int,\n    n_row: int\n) -> List[str]:\n    \"\"\"\n    Validate generated data structure against expected format.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        Generated dataframe\n    n_buyer : int\n        Expected number of buyers\n    S : int\n        Expected number of state dimensions\n    A : int\n        Expected number of actions\n    n_row : int\n        Expected number of rows\n    \n    Returns\n    -------\n    List[str]\n        List of error messages (empty if validation passes)\n    \"\"\"\n    \n    errors = []\n    \n    # Check shape\n    expected_cols = 2 + S + A + S + 1  # 778 for default values\n    if df.shape[1] != expected_cols:\n        errors.append(f\"Column count: expected {expected_cols}, got {df.shape[1]}\")\n    \n    if df.shape[0] != n_row:\n        errors.append(f\"Row count: expected {n_row}, got {df.shape[0]}\")\n    \n    # Check column names\n    expected_cols_list = ['buyer_id', 'receive_time_id']\n    expected_cols_list += [f's{i}' for i in range(1, S + 1)]\n    expected_cols_list += [f'a{i}' for i in range(1, A + 1)]\n    expected_cols_list += [f'ns{i}' for i in range(1, S + 1)]\n    expected_cols_list += ['div_pay_amt_fillna']\n    \n    missing_cols = set(expected_cols_list) - set(df.columns)\n    if missing_cols:\n        errors.append(f\"Missing columns: {missing_cols}\")\n    \n    extra_cols = set(df.columns) - set(expected_cols_list)\n    if extra_cols:\n        errors.append(f\"Unexpected columns: {extra_cols}\")\n    \n    # Check data types\n    if df['buyer_id'].dtype not in [np.int64, np.int32, np.int16, int]:\n        errors.append(f\"buyer_id dtype: expected int, got {df['buyer_id'].dtype}\")\n    \n    if df['receive_time_id'].dtype not in [np.int64, np.int32, np.int16, int]:\n        errors.append(f\"receive_time_id dtype: expected int, got {df['receive_time_id'].dtype}\")\n    \n    # Check state columns are numeric\n    state_cols = [f's{i}' for i in range(1, S + 1)]\n    for col in state_cols:\n        if not np.issubdtype(df[col].dtype, np.number):\n            errors.append(f\"{col} dtype: expected numeric, got {df[col].dtype}\")\n    \n    # Check action columns are binary (one-hot encoded)\n    action_cols = [f'a{i}' for i in range(1, A + 1)]\n    for col in action_cols:\n        if not all(df[col].isin([0, 1])):\n            errors.append(f\"{col}: action column should be binary (0/1)\")\n    \n    # Check outcome is non-negative\n    if (df['div_pay_amt_fillna'] < 0).any():\n        errors.append(\"Outcome has negative values (should be >= 0)\")\n    \n    # Check buyer_id range\n    if df['buyer_id'].min() < 1 or df['buyer_id'].max() > n_buyer:\n        errors.append(f\"buyer_id range: expected [1, {n_buyer}], got [{df['buyer_id'].min()}, {df['buyer_id'].max()}]\")\n    \n    # Check receive_time_id per buyer\n    max_receive_time = df.groupby('buyer_id')['receive_time_id'].max()\n    if not (max_receive_time >= 10).all():\n        errors.append(\"Some buyers have fewer than 10 observations\")\n    \n    return errors\n\n\ndef save_data(df: pd.DataFrame, output_path: str = 'data/raw/simulated_data.txt'):\n    \"\"\"\n    Save generated data to CSV file.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        DataFrame to save\n    output_path : str\n        Path to save CSV file\n    \"\"\"\n    logger.info(f\"Saving data to {output_path}...\")\n    df.to_csv(output_path, index=False)\n    logger.info(f\"  ✓ Data saved successfully\")\n    \n    # Print file info\n    file_size_mb = os.path.getsize(output_path) / (1024 * 1024)\n    logger.info(f\"  File size: {file_size_mb:.2f} MB\")\n\n\ndef summary_statistics(df: pd.DataFrame, output_path: str = 'output/tables/data_summary.csv'):\n    \"\"\"\n    Generate and save summary statistics.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        Generated data\n    output_path : str\n        Path to save summary statistics\n    \"\"\"\n    logger.info(f\"Generating summary statistics...\")\n    \n    summary = pd.DataFrame({\n        'Column': df.columns,\n        'Dtype': df.dtypes.values,\n        'Non-Null Count': df.count().values,\n        'Null Count': df.isnull().sum().values,\n        'Mean': df.mean(numeric_only=True).reindex(df.columns).values,\n        'Std': df.std(numeric_only=True).reindex(df.columns).values,\n        'Min': df.min(numeric_only=True).reindex(df.columns).values,\n        'Max': df.max(numeric_only=True).reindex(df.columns).values,\n    })\n    \n    summary.to_csv(output_path, index=False)\n    logger.info(f\"  ✓ Summary statistics saved to {output_path}\")\n    \n    # Log key statistics\n    logger.info(f\"\\nData Summary:\")\n    logger.info(f\"  Observations: {df.shape[0]}\")\n    logger.info(f\"  Columns: {df.shape[1]}\")\n    logger.info(f\"  Buyers: {df['buyer_id'].nunique()}\")\n    logger.info(f\"  Max trajectory length: {df.groupby('buyer_id')['receive_time_id'].max().max()}\")\n    logger.info(f\"  Outcome (div_pay_amt_fillna):\")\n    logger.info(f\"    Mean: {df['div_pay_amt_fillna'].mean():.4f}\")\n    logger.info(f\"    Std: {df['div_pay_amt_fillna'].std():.4f}\")\n    logger.info(f\"    Min: {df['div_pay_amt_fillna'].min():.4f}\")\n    logger.info(f\"    Max: {df['div_pay_amt_fillna'].max():.4f}\")\n    logger.info(f\"    % Non-zero: {(df['div_pay_amt_fillna'] > 0).sum() / len(df) * 100:.1f}%\")\n\n\ndef main():\n    \"\"\"\n    Main execution function.\n    \"\"\"\n    logger.info(\"=\"*80)\n    logger.info(\"REPLICATION PROJECT: DATA GENERATION\")\n    logger.info(\"=\"*80)\n    \n    try:\n        # Generate data\n        df = generate_simulated_data(\n            n_buyer=10,  # Start with small sample for testing\n            S=375,\n            A=25,\n            seed=42,\n            verbose=True\n        )\n        \n        # Save data\n        save_data(df, 'data/raw/simulated_data.txt')\n        \n        # Generate summary statistics\n        summary_statistics(df, 'output/tables/data_summary.csv')\n        \n        logger.info(\"\\n\" + \"=\"*80)\n        logger.info(\"✓ DATA GENERATION COMPLETE\")\n        logger.info(\"=\"*80)\n        logger.info(f\"Next steps:\")\n        logger.info(f\"  1. Review data in: data/raw/simulated_data.txt\")\n        logger.info(f\"  2. Check summary: output/tables/data_summary.csv\")\n        logger.info(f\"  3. Continue with: python code/02_model_free.py\")\n        logger.info(\"=\"*80)\n        \n        return df\n    \n    except Exception as e:\n        logger.error(f\"\\n✗ ERROR during data generation: {str(e)}\")\n        logger.exception(\"Full traceback:\")\n        sys.exit(1)\n\n\nif __name__ == '__main__':\n    df = main()\n"